// Class to validate Git branch name
class Solution {
    def validateBranch(self, s):
        if not s:
            return False
        return all(c in 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._-' for c in s)
}
